[CmdletBinding()]param([Parameter(Mandatory)][string]$ProjectRoot,[ValidateSet('lean','standard','thorough')][string]$Mode='standard')
$ErrorActionPreference='Stop';. (Join-Path $PSScriptRoot '../records/Test-RequiredProjectRecords.ps1')
$project=(Resolve-Path -LiteralPath $ProjectRoot).Path;$req=Get-StudioRequirements $project;if(-not $req.state.valid){throw 'Cannot resolve rules without valid machine-readable project state.'};$root=(Resolve-Path (Join-Path $PSScriptRoot '../..')).Path;$index=Get-Content -Raw (Join-Path $root 'knowledge/context/RULE_ROUTE_INDEX.json')|ConvertFrom-Json;$mapPath=Join-Path $project '.studio/REPO_MAP.json';if(-not(Test-Path $mapPath)){& (Join-Path $PSScriptRoot 'build_repo_map.ps1') -ProjectRoot $project|Out-Null};$map=Get-Content -Raw $mapPath|ConvertFrom-Json;$stack=@($map.frameworks)+@($map.languages)
$rules=@($index.rules|Where-Object{($_.productTypes.Count -eq 0 -or $_.productTypes -contains $req.productType) -and ($_.surfaces.Count -eq 0 -or @($_.surfaces|Where-Object{$req.surfaces -contains $_}).Count) -and ($_.stacks.Count -eq 0 -or @($_.stacks|Where-Object{$stack -contains $_}).Count)}|Sort-Object @{e='priority';Descending=$true},id);$context=Join-Path $project '.studio/context';New-Item -ItemType Directory -Force -Path $context|Out-Null;[ordered]@{schemaVersion=1;generatedAt=[DateTime]::UtcNow.ToString('o');workflowMode=$req.workflowMode;productType=$req.productType;surfaces=@($req.surfaces);stack=@($stack|Sort-Object -Unique);activeHardRules=@($rules|Where-Object{$_.strength -eq 'hard'});activePreferences=@($rules|Where-Object{$_.strength -ne 'hard'});sourcePaths=@($rules|ForEach-Object source|Sort-Object -Unique)}|ConvertTo-Json -Depth 10|Set-Content -LiteralPath (Join-Path $context 'RESOLVED_RULES.json') -Encoding utf8
